// 1. typeof ilə Type Guard
function printValue(value: string | number) {
  if (typeof value === "string") {
    console.log("String: " + value.toUpperCase());
  } else {
    console.log("Number: " + value.toFixed(2));
  }
}
printValue("Hello"); // Çıxış: String: HELLO
printValue(42); // Çıxış: Number: 42.00

// 2. instanceof ilə Type Guard
class Dog {
  bark() { return "Woof"; }
}
class Cat {
  meow() { return "Meow"; }
}
function makeSound(animal: Dog | Cat) {
  if (animal instanceof Dog) {
    console.log(animal.bark());
  } else {
    console.log(animal.meow());
  }
}
const dog = new Dog();
const cat = new Cat();
makeSound(dog); // Çıxış: Woof
makeSound(cat); // Çıxış: Meow

// 3. in Operatoru ilə Type Guard
interface User {
  name: string;
}
interface Admin {
  role: string;
}
function getRole(person: User | Admin) {
  if ("role" in person) {
    console.log("Role: " + person.role);
  } else {
    console.log("Name: " + person.name);
  }
}
const user: User = { name: "Alice" };
const admin: Admin = { role: "manager" };
getRole(user); // Çıxış: Name: Alice
getRole(admin); // Çıxış: Role: manager

// 4. User-Defined Type Guard
function isString(value: any): value is string {
  return typeof value === "string";
}
function processValue(value: string | number) {
  if (isString(value)) {
    console.log("String: " + value.toUpperCase());
  } else {
    console.log("Number: " + value.toFixed(2));
  }
}
processValue("Test"); // Çıxış: String: TEST
processValue(123.456); // Çıxış: Number: 123.46

// 5. Discriminated Unions ilə Type Guard
interface Circle {
  kind: "circle";
  radius: number;
}
interface Square {
  kind: "square";
  side: number;
}
type Shape = Circle | Square;
function getArea(shape: Shape) {
  switch (shape.kind) {
    case "circle":
      return 3.14 * shape.radius * shape.radius;
    case "square":
      return shape.side * shape.side;
  }
}
const circle: Circle = { kind: "circle", radius: 5 };
const square: Square = { kind: "square", side: 4 };
console.log(getArea(circle)); // Çıxış: 78.5
console.log(getArea(square)); // Çıxış: 16

// Sadə mağaza sistemi
interface PhysicalProduct {
  type: "physical";
  weight: number;
  name: string;
}
interface DigitalProduct {
  type: "digital";
  fileSize: number;
  name: string;
}
type Product = PhysicalProduct | DigitalProduct;

// Discriminated Union ilə Type Guard
function getProductInfo(product: Product) {
  if (product.type === "physical") {
    return `Physical: ${product.name}, Weight: ${product.weight}kg`;
  } else {
    return `Digital: ${product.name}, Size: ${product.fileSize}MB`;
  }
}
const laptop: PhysicalProduct = { type: "physical", name: "Laptop", weight: 2 };
const ebook: DigitalProduct = { type: "digital", name: "E-book", fileSize: 10 };
console.log(getProductInfo(laptop)); // Çıxış: Physical: Laptop, Weight: 2kg
console.log(getProductInfo(ebook)); // Çıxış: Digital: E-book, Size: 10MB

// User-Defined Type Guard ilə
function isPhysicalProduct(product: Product): product is PhysicalProduct {
  return product.type === "physical";
}
function processProduct(product: Product) {
  if (isPhysicalProduct(product)) {
    console.log(`Shipping ${product.name} with ${product.weight}kg`);
  } else {
    console.log(`Downloading ${product.name}, ${product.fileSize}MB`);
  }
}
processProduct(laptop); // Çıxış: Shipping Laptop with 2kg
processProduct(ebook); // Çıxış: Downloading E-book, 10MB

